def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        additive = 0.0
        multiplier = 1.0
        for j in range(1, 15):
            if j % 5 == 0:
                decay *= 0.85
            if ratio < (0.04 * j):
                increment = (j ** 1.7) * np.exp(-ratio*j) * decay
                if (cap + item) % (j + 2) == 0:
                    increment += np.log1p(j*2)
                else:
                    increment -= np.sqrt(j) * 0.5
                score += increment
            else:
                increment = j * np.cos(ratio * j) * decay / (j + 2)
                if (cap * j) % 4 == 0:
                    increment += np.sin(ratio * j * 1.5)
                else:
                    increment -= np.tanh(ratio * j)
                score += increment
            if j % 3 == 0:
                additive += np.tanh(score / (j + 0.5)) * (j / 10)
            else:
                additive -= np.arctan(score / (j + 1)) * (j / 15)
            if (j + i) % 7 == 0:
                multiplier *= 1 + 0.01 * j
            else:
                multiplier *= 1 - 0.005 * j
        for k in range(1, 7):
            residual = cap - item * k
            sign_factor = 1 if (residual % (k+1)) == 0 else -1
            if residual > 0:
                bonus = (residual ** 0.3) * sign_factor / (k + 0.7)
                if (residual + k) % 5 == 0:
                    bonus += np.log1p(k)
                else:
                    bonus -= np.sqrt(k) * 0.3
                score += bonus
            else:
                penalty = abs(residual) * 0.15 * k * sign_factor
                if residual % 2 == 0:
                    penalty *= 1.2
                else:
                    penalty *= 0.8
                score -= penalty
        final_value = ((score + additive) * multiplier) / (cap + 2)
        if final_value > 0:
            peaks = 0.0
            for p in range(1, 4):
                peaks += np.sin(final_value * p) / (p + 1)
            priorities[i] = -final_value * np.exp(-ratio) + peaks
        else:
            valleys = 0.0
            for q in range(1, 5):
                valleys -= np.cos(final_value * q) / (q + 0.5)
            priorities[i] = -final_value * (np.log1p(cap) + np.sqrt(item)) + valleys
    return priorities
